{
  "strategy": "Use the known Wild Shuffle Hands interval, retrieve a small chronological frame set spanning the redeal/result, and visually count how many of the four players' post-shuffle hands contain at least one red card.",
  "steps": [
    {
      "step_id": 1,
      "tool_name": "frame_retriever",
      "purpose": "Retrieve chronological frames around the Wild Shuffle Hands demonstration, especially after the redeal when all players' hands are visible or individually shown, so the post-shuffle card colors can be verified.",
      "inputs": {
